    17→import MyOrdersCashbackView from './view';
    18→
    19→const MyOrdersCashback = () => {
    20→  const [isRefreshing, setIsRefreshing] = useState(false);
    21→
    22→  const modalizeRefFilters = useRef<PropsModalizeRef>(null);
    23→  const emptyImage =
    24→    'https://image.mkt-semparar.com.br/lib/fe2f117170640475721171/m/1/shopping_cart.png';
    25→
    26→  const SKELETON_COUNT = 3;
    27→  const { width } = Dimensions.get('window');
    28→
    29→  const navigation = useNavigation<NavigationProp<PropsRootStack>>();
    30→
    31→  const { pointsExtract } = useRootStore(
    32→    useShallow(state => ({
    33→      pointsExtract: state.pointsExtract,
    34→    })),
    35→  );
    36→
    37→  const filtersPeriod = [
    38→    { label: '7 dias', value: 7 },
    39→    { label: '15 dias', value: 15 },
    40→    { label: '30 dias', value: 30 },
    41→    { label: '60 dias', value: 60 },
    42→    { label: '90 dias', value: 90 },
    43→  ];
    44→
    45→  const getFormatDate = (iso?: string) => {
    46→    if (!iso) return '';
    47→    const date = parseISO(iso);
    48→    return format(date, 'dd/MM/yyyy');
    49→  };
    50→
    51→  const filterGroups: FilterGroup[] = [
    52→    {
    53→      label: 'Períodos',
    54→      options: filtersPeriod,
