    61→      ],
    62→    },
    63→  ];
    64→
    65→  const handleOpenFilters = () => {
    66→    eventSelectContent({
    67→      content_type: 'cta',
    68→      content_id: 'filtro_pedidos',
    69→      location_1: 'monetizacao',
    70→      location_2: 'hub_recompensas_spmais',
    71→      location_3: 'meus_pedidos',
    72→    });
    73→
    74→    modalizeRefFilters.current?.open?.();
    75→  };
    76→
    77→  const handleDetailsOrders = (
    78→    transactionId: string,
    79→    type?: string,
    80→    icon?: string,
    81→    status?: string,
    82→    origination?: string,
    83→  ) => {
    84→    eventSelectContent({
    85→      content_type: 'cta',
    86→      content_id: 'detalhe_pedido',
    87→      location_1: 'monetizacao',
    88→      location_2: 'hub_recompensas_spmais',
    89→      location_3: 'meus_pedidos',
    90→    });
    91→
    92→    navigation.navigate('MyOrdersDetails', {
    93→      transactionId,
    94→      type,
    95→      icon,
    96→      status,
    97→      origination,
    98→      analytics: {
    99→        screen_name: 'detalhe_pedido',
   100→        screen_class: 'hub_recompensas_spmais',
   101→        screen_bussines: 'monetizacao',
   102→        screen_info: {
   103→          location_1: 'monetizacao',
   104→          location_2: 'hub_recompensas_spmais',
   105→          location_3: 'detalhe_pedido',
   106→        },
   107→      },
   108→    });
   109→  };
   110→
   111→  const myOrders = pointsExtract?.extractData?.transactions || [];
   112→
   113→  const isLoading = pointsExtract.status === PointsExtractStatus.LOADING;
   114→  const isError = pointsExtract.status === PointsExtractStatus.ERROR;
   115→
   116→  const handleGoBack = () => {
   117→    navigation.goBack();
   118→  };
   119→
   120→  const handleRefresh = async () => {
   121→    setIsRefreshing(true);
   122→    await getPointsExtract({ type: 'Resgate' });
   123→    setIsRefreshing(false);
   124→  };
   125→
   126→  const hasFocused = useRef(false);
   127→  useFocusEffect(
   128→    React.useCallback(() => {
   129→      if (!hasFocused.current) {
   130→        eventScreenViewV3(
   131→          'meus_pedidos',
   132→          'hub_recompensas_spmais',
   133→          'monetizacao',
   134→          {
   135→            location_1: 'monetizacao',
   136→            location_2: 'hub_recompensas_spmais',
   137→            location_3: 'meus_pedidos',
   138→          },
   139→        );
   140→        getPointsExtract({ type: 'Resgate' });
   141→        hasFocused.current = true;
   142→      }
   143→      return () => {
   144→        hasFocused.current = false;
   145→      };
   146→    }, []),
   147→  );
   148→
   149→  return (
   150→    <MyOrdersCashbackView
   151→      myOrders={myOrders}
   152→      emptyImage={emptyImage}
   153→      isLoading={isLoading}
   154→      isError={isError}
   155→      filterGroups={filterGroups}
   156→      modalizeRefFilters={modalizeRefFilters}
   157→      formatDate={getFormatDate}
   158→      handleGoBack={handleGoBack}
   159→      handleOpenFilters={handleOpenFilters}
   160→      handleDetailsOrders={handleDetailsOrders}
   161→      isRefreshing={isRefreshing}
   162→      handleRefresh={handleRefresh}
   163→      skeletonCount={SKELETON_COUNT}
   164→      screenWidth={width}
   165→    />
   166→  );
   167→};
   168→
   169→export default MyOrdersCashback;
